(window.webpackJsonp=window.webpackJsonp||[]).push([[1369],{1638:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">x</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">y</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> isCousins = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root, x, y</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n  <span class=\\"hljs-keyword\\">let</span> xd,xp,yd,yp\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">root,parent,deep</span>)</span>{\\n    root.p=parent\\n    root.d=deep\\n    <span class=\\"hljs-keyword\\">if</span>(root.val===x){\\n      xd=deep\\n      xp=parent\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(root.val===y){\\n      yd=deep\\n      yp=parent\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(root.left)dfs(root.left,root,deep+<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">if</span>(root.right)dfs(root.right,root,deep+<span class=\\"hljs-number\\">1</span>)\\n  }\\n  dfs(root,<span class=\\"hljs-literal\\">null</span>,<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-comment\\">// console.log(xd,yd,xp,yp)</span>\\n  <span class=\\"hljs-keyword\\">if</span>(xd===yd &amp;&amp; xp!==yp)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n};\\n</code></pre>\\n"],"titleSlug":"cousins-in-binary-tree","hasThinking":false,"content":"<p>\u5728\u4e8c\u53c9\u6811\u4e2d\uff0c\u6839\u8282\u70b9\u4f4d\u4e8e\u6df1\u5ea6 <code>0</code> \u5904\uff0c\u6bcf\u4e2a\u6df1\u5ea6\u4e3a <code>k</code> \u7684\u8282\u70b9\u7684\u5b50\u8282\u70b9\u4f4d\u4e8e\u6df1\u5ea6 <code>k+1</code> \u5904\u3002</p>\\n\\n<p>\u5982\u679c\u4e8c\u53c9\u6811\u7684\u4e24\u4e2a\u8282\u70b9\u6df1\u5ea6\u76f8\u540c\uff0c\u4f46<strong> \u7236\u8282\u70b9\u4e0d\u540c</strong> \uff0c\u5219\u5b83\u4eec\u662f\u4e00\u5bf9<em>\u5802\u5144\u5f1f\u8282\u70b9</em>\u3002</p>\\n\\n<p>\u6211\u4eec\u7ed9\u51fa\u4e86\u5177\u6709\u552f\u4e00\u503c\u7684\u4e8c\u53c9\u6811\u7684\u6839\u8282\u70b9 <code>root</code> \uff0c\u4ee5\u53ca\u6811\u4e2d\u4e24\u4e2a\u4e0d\u540c\u8282\u70b9\u7684\u503c <code>x</code> \u548c <code>y</code> \u3002</p>\\n\\n<p>\u53ea\u6709\u4e0e\u503c <code>x</code> \u548c <code>y</code> \u5bf9\u5e94\u7684\u8282\u70b9\u662f\u5802\u5144\u5f1f\u8282\u70b9\u65f6\uff0c\u624d\u8fd4\u56de <code>true</code> \u3002\u5426\u5219\uff0c\u8fd4\u56de <code>false</code>\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a<br />\\n<img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/02/16/q1248-01.png\\" style=\\"height: 160px; width: 180px;\\" /></strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2,3,4], x = 4, y = 3\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a<br />\\n<img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/02/16/q1248-02.png\\" style=\\"height: 160px; width: 201px;\\" /></strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2,3,null,4,null,5], x = 5, y = 4\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/02/16/q1248-03.png\\" style=\\"height: 160px; width: 156px;\\" /></strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2,3,null,4], x = 2, y = 3\\n<strong>\u8f93\u51fa\uff1a</strong>false</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u4e8c\u53c9\u6811\u7684\u8282\u70b9\u6570\u4ecb\u4e8e\xa0<code>2</code> \u5230\xa0<code>100</code>\xa0\u4e4b\u95f4\u3002</li>\\n\\t<li>\u6bcf\u4e2a\u8282\u70b9\u7684\u503c\u90fd\u662f\u552f\u4e00\u7684\u3001\u8303\u56f4\u4e3a\xa0<code>1</code> \u5230\xa0<code>100</code>\xa0\u7684\u6574\u6570\u3002</li>\\n</ul>\\n\\n<p>\xa0</p>\\n","title":"993. \u4e8c\u53c9\u6811\u7684\u5802\u5144\u5f1f\u8282\u70b9","relatedTags":["\u6811","\u5e7f\u5ea6\u4f18\u5148\u641c\u7d22"],"difficult":"Easy","lang":["javascript"],"uniqueID":"993"}')}}]);